UPDATE recipes
SET instructions = '["To make the Sauce", "In a pan add all the ingredients, including the Spring Onions and Pineapple, except the Cornflour mixture, Cider, Flour and Tiger Prawns", "Bring to the boil then simmer about 5-6 minutes, or until the sauce is reduced a little", "Mix together again the Cornflour and Chicken Stock and add slowly to the pan until it begins to thicken slightly", "Heat a deep fat fryer to 180 degrees C ", "Mix together the Self Raising Flour and sufficient Cider to make a batter", "Add a large pinch of Sea Salt", "Coat the Prawns in the mixture and deep fry in batches until golden and crisp ", "About 2 to 3 minutes ", "Drain season with salt", "To Serve", "Add the Pineapple to the Sauce and allow to warm through", "Divide the Sauce between 2 plates", "Serve the Prawns on top, sprinkled with Spring Onions and Coriander", "To indulge, add some fries"]'::jsonb
WHERE slug = 'sweet-and-sour-prawns';